import sys
from collections import deque

class Solution:
    def __init__(self):
        self.q = deque()

    def push(self, x: int) -> None:
        self.q.append(x)
        for _ in range(len(self.q) - 1):
            self.q.append(self.q.popleft())

    def pop(self) -> int:
        if not self.q:
            return -1
        return self.q.popleft()

    def top(self) -> int:
        if not self.q:
            return -1
        return self.q[0]

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        Q = int(next(it))
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    for _ in range(Q):
        query = next(it)
        if query == 'push':
            x = int(next(it))
            sol.push(x)
        elif query == 'pop':
            print(sol.pop())
        elif query == 'top':
            print(sol.top())

