#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    queue<int> q;

    void push(int x) {
        q.push(x);
        for (int i = 0; i < q.size() - 1; i++) {
            q.push(q.front());
            q.pop();
        }
    }

    int pop() {
        if (q.empty()) {
            return -1;
        }
        int res = q.front();
        q.pop();
        return res;
    }

    int top() {
        if (q.empty()) {
            return -1;
        }
        return q.front();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int Q;
    if (!(cin >> Q)) return 0;
    Solution sol;
    for (int i = 0; i < Q; i++) {
        string query;
        if (!(cin >> query)) return 0;
        if (query == "push") {
            int x;
            if (!(cin >> x)) return 0;
            sol.push(x);
        } else if (query == "pop") {
            cout << sol.pop() << "\n";
        } else if (query == "top") {
            cout << sol.top() << "\n";
        }
    }
    return 0;
}
